/**
 * Source-loading helper. Reads the primitive's markdown into the test
 * scope so behavioural assertions can grep against the live source. The
 * lookup walks up from `process.cwd()` (the host repo) and prefers an
 * env-var override (`ZOTO_EVAL_REPO_ROOT`) for nested executions.
 */
function loadPrimitiveSource(): string | null {
  const root = process.env.ZOTO_EVAL_REPO_ROOT ?? process.cwd();
  const abs = resolve(root, SOURCE_PATH);
  if (!existsSync(abs)) return null;
  return readFileSync(abs, "utf-8");
}

